body:
There is an issue when trying to access arrays through VPI using cocotb as reported in #2105 . I've investigated this further since #2347 has been merged and believe the root cause is due to vpi_iterate(vpiRange). 

Below is a test that replicates the relevant steps when cocotb initialises access to a multi-dimensional array:

```diff
diff --git a/test_regress/t/t_vpi_memory.cpp b/test_regress/t/t_vpi_memory.cpp
index 5b229b78..cd6bb7d1 100644
--- a/test_regress/t/t_vpi_memory.cpp
+++ b/test_regress/t/t_vpi_memory.cpp
@@ -158,6 +158,39 @@ int _mon_check_memory() {
     CHECK_RESULT(should_be_NULL, 0);
     should_be_NULL = vpi_handle(vpiScope, iter_h);
     CHECK_RESULT(should_be_NULL, 0);
+
+    // vpi_iterate(vpiRange)
+    s_vpi_value val = {.format = vpiIntVal, .value = {.integer = 0}};
+    int vpi_type;
+    vpi_printf((PLI_BYTE8*)"\nCheck vpi_iterate(vpiRange) ...\n");
+    vpiHandle array_h, itr_h, range_h, left_h;
+    array_h = vpi_handle_by_name((PLI_BYTE8*)TestSimulator::rooted("mem0"), NULL);
+    vpi_type = vpi_get(vpiType, array_h);
+    vpi_printf((PLI_BYTE8*)"    array_h %p name: '%s' vpiType: %s(%d)\n", array_h, vpi_get_str(vpiFullName, array_h), vpi_get_str(vpiType, array_h), vpi_type);
+
+    itr_h = vpi_iterate(vpiRange, array_h);
+    CHECK_RESULT_NZ(itr_h);
+    if (itr_h != NULL) {
+        vpi_type = vpi_get(vpiType, itr_h);
+        vpi_printf((PLI_BYTE8*)"    itr_h %p name: '%s' vpiType: %s(%d)\n", itr_h, vpi_get_str(vpiFullName, itr_h), vpi_get_str(vpiType, itr_h), vpi_type);
+
+        range_h = vpi_scan(itr_h);
+        CHECK_RESULT_NZ(itr_h);
+        if (range_h != NULL) {
+            vpi_type = vpi_get(vpiType, range_h);
+            vpi_printf((PLI_BYTE8*)"    range_h %p name: '%s' vpiType: %s(%d)\n", range_h, vpi_get_str(vpiFullName, range_h), vpi_get_str(vpiType, range_h), vpi_type);
+
+            left_h = vpi_handle(vpiLeftRange, range_h);
+//            CHECK_RESULT_NZ(left_h);
+            vpi_type = vpi_get(vpiType, left_h);
+            vpi_printf((PLI_BYTE8*)"    left_h %p name: '%s' vpiType: %s(%d)\n", left_h, vpi_get_str(vpiFullName, left_h), vpi_get_str(vpiType, left_h), vpi_type);
+
+            vpi_get_value(left_h, &val);
+            vpi_printf((PLI_BYTE8*)"    left range value: %d\n", val.value.integer);
+            CHECK_RESULT(val.value.integer, 16);
+        }
+    }
+
     return 0;  // Ok
 }
``` 
The issue is that ```left_h = vpi_handle(vpiLeftRange, range_h);``` is returning ```null``` rather than a valid vpi_handle. This is because ```vpi_handle(vpiLeftRange, handle)``` is not implemented for ```vpiRange``` object handles.

